// ⚙️  KONFIGURASI — WAJIB diubah!
const FITFLOW_BASE_URL  = 'http://localhost:3000';
const FITFLOW_SECRET    = 'fitflow_nr_7x9k2m_secret';
const USER_ID           = 'GANTI_DENGAN_UUID_INSTRUKTUR';
const INSTRUCTOR_PHONE  = '628xxxxxxxxx'; // format 628...
// ─────────────────────────────────────────────

msg.url    = FITFLOW_BASE_URL + '/api/ai/daily-summary';
msg.method = 'POST';
msg.headers = {
    'x-webhook-secret': FITFLOW_SECRET,
    'Content-Type': 'application/json'
};
msg.payload          = JSON.stringify({ user_id: USER_ID });
msg.instructorPhone  = INSTRUCTOR_PHONE;
msg.fitflowBaseUrl   = FITFLOW_BASE_URL;
msg.fitflowSecret    = FITFLOW_SECRET;
return msg;

// ⚙️  KONFIGURASI
const FONNTE_TOKEN = 'GANTI_DENGAN_TOKEN_FONNTE_KAMU';
// ─────────────────────────────────────────────

if (!msg.payload || !msg.payload.ok) {
    node.warn('Daily summary gagal: ' + JSON.stringify(msg.payload));
    return null;
}

const summary = msg.payload.summary;
let phone = (msg.instructorPhone || '').replace(/\D/g, '');
if (phone.startsWith('0')) phone = '62' + phone.slice(1);

msg.url    = 'https://api.fonnte.com/send';
msg.method = 'POST';
msg.headers = {
    'Authorization': FONNTE_TOKEN,
    'Content-Type': 'application/json'
};
msg.payload = JSON.stringify({
    target:      phone,
    message:     summary,
    countryCode: '62'
});
return msg;

// ⚙️  KONFIGURASI
const FITFLOW_BASE_URL = 'http://localhost:3000';
const FITFLOW_SECRET   = 'fitflow_nr_7x9k2m_secret';
// ─────────────────────────────────────────────

msg.url    = FITFLOW_BASE_URL + '/api/webhooks/nodered';
msg.method = 'POST';
msg.headers = {
    'x-webhook-secret': FITFLOW_SECRET,
    'Content-Type': 'application/json'
};
msg.payload = JSON.stringify({ action: 'get_pending_recipients', limit: 20 });

// Simpan config agar bisa dipakai node berikutnya
msg.fitflowBaseUrl = FITFLOW_BASE_URL;
msg.fitflowSecret  = FITFLOW_SECRET;
return msg;

if (!msg.payload || !msg.payload.ok ||
    !msg.payload.recipients ||
    msg.payload.recipients.length === 0) {
    return null; // tidak ada broadcast pending — stop
}
msg.payload = msg.payload.recipients;
return msg;

// ⚙️  KONFIGURASI
const FONNTE_TOKEN = 'GANTI_DENGAN_TOKEN_FONNTE_KAMU';
// ─────────────────────────────────────────────

const recipient = msg.payload;
// broadcast bisa array (Supabase foreign key expand) atau object
const bc = Array.isArray(recipient.broadcast)
    ? recipient.broadcast[0]
    : recipient.broadcast;

// Simpan untuk digunakan setelah WA terkirim
msg.recipientId   = recipient.id;
// Teruskan config dari node sebelumnya
msg.fitflowBaseUrl = msg.fitflowBaseUrl || 'http://localhost:3000';
msg.fitflowSecret  = msg.fitflowSecret  || 'fitflow_nr_7x9k2m_secret';

// Format nomor HP (pastikan format 62xxx)
let phone = (recipient.phone || '').replace(/\D/g, '');
if (phone.startsWith('0')) phone = '62' + phone.slice(1);

msg.url    = 'https://api.fonnte.com/send';
msg.method = 'POST';
msg.headers = {
    'Authorization': FONNTE_TOKEN,
    'Content-Type': 'application/json'
};
msg.payload = JSON.stringify({
    target:      phone,
    message:     bc ? bc.content : 'Halo dari FitFlow Coach!',
    countryCode: '62'
});
return msg;

// Fonnte mengembalikan { status: true, ... } jika berhasil
const waOk = msg.statusCode === 200 &&
             msg.payload && msg.payload.status === true;

msg.url    = msg.fitflowBaseUrl + '/api/webhooks/nodered';
msg.method = 'POST';
msg.headers = {
    'x-webhook-secret': msg.fitflowSecret,
    'Content-Type': 'application/json'
};
msg.payload = JSON.stringify({
    action:       'mark_recipient',
    recipient_id: msg.recipientId,
    status:       waOk ? 'sent' : 'failed'
});
return msg;
